at::Tensor max_pooling_1d_impl_npu(const at::Tensor& self, int64_t kernel_size, c10::optional<int64_t> stride_opt, int64_t padding, bool return_indices) {
    int64_t stride = stride_opt.has_value() ? stride_opt.value() : kernel_size;
    at::Tensor result = at::empty({self.size(0), self.size(1),
                                   (self.size(2) + 2 * padding - (kernel_size - 1) - 1) / stride + 1},
                                   self.options());
    // Only y output supported; return_indices ignored
    EXEC_NPU_CMD(aclnnMaxPooling1dCustom, self, static_cast<int>(kernel_size), static_cast<int>(stride), static_cast<int>(padding), return_indices, result);
    return result;
